class Solution:
    def numberOfRoutes(self, grid, d):
        # Independent check: plain memoized recursion with direct nested-loop
        # distance checks (no prefix-sum window trick), only ever run by this
        # pack on small grids.
        MOD = 10 ** 9 + 7
        n = len(grid)
        m = len(grid[0])
        avail = [[ch == '.' for ch in row] for row in grid]
        d2 = d * d
        import sys
        sys.setrecursionlimit(10000)
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def ways_false(r, c):
            # arrivals at (r, c) where the previous step (if any) was NOT lateral
            if not avail[r][c]:
                return 0
            total = 1 if r == n - 1 else 0
            if r < n - 1:
                for c2 in range(m):
                    if not avail[r + 1][c2]:
                        continue
                    dc = c - c2
                    if 1 + dc * dc <= d2:
                        total += ways_false(r + 1, c2) + ways_true(r + 1, c2)
            return total % MOD

        @lru_cache(maxsize=None)
        def ways_true(r, c):
            # arrivals at (r, c) where the previous step was lateral
            if not avail[r][c]:
                return 0
            total = 0
            for c2 in range(m):
                if c2 == c or not avail[r][c2]:
                    continue
                dc = c - c2
                if dc * dc <= d2:
                    total += ways_false(r, c2)
            return total % MOD

        ans = 0
        for c in range(m):
            ans = (ans + ways_false(0, c) + ways_true(0, c)) % MOD
        return ans

