var numberOfRoutes = function(grid, d) {
    const MOD = 1000000007n;
    const n = grid.length;
    const m = grid[0].length;
    const avail = grid.map(row => row.split('').map(ch => ch === '.'));
    const latBound = d;
    const vBoundSq = d * d - 1;
    const vBound = vBoundSq >= 0 ? Math.floor(Math.sqrt(vBoundSq) + 1e-9) : -1;

    function lateralPass(falseVals, availRow) {
        const prefix = new Array(m + 1).fill(0n);
        for (let c = 0; c < m; c++) {
            prefix[c + 1] = (prefix[c] + falseVals[c]) % MOD;
        }
        const trueVals = new Array(m).fill(0n);
        for (let c = 0; c < m; c++) {
            if (!availRow[c]) continue;
            const lo = Math.max(0, c - latBound);
            const hi = Math.min(m - 1, c + latBound);
            let s = (prefix[hi + 1] - prefix[lo]) % MOD;
            s = (s - falseVals[c]) % MOD;
            if (s < 0n) s += MOD;
            trueVals[c] = s;
        }
        return trueVals;
    }

    let rowFalse = new Array(m).fill(0n);
    for (let c = 0; c < m; c++) rowFalse[c] = avail[n - 1][c] ? 1n : 0n;
    let rowTrue = lateralPass(rowFalse, avail[n - 1]);
    let rowTotal = new Array(m);
    for (let c = 0; c < m; c++) rowTotal[c] = (rowFalse[c] + rowTrue[c]) % MOD;

    for (let r = n - 2; r >= 0; r--) {
        const prefix = new Array(m + 1).fill(0n);
        for (let c = 0; c < m; c++) {
            prefix[c + 1] = (prefix[c] + rowTotal[c]) % MOD;
        }
        const newFalse = new Array(m).fill(0n);
        if (vBound >= 0) {
            for (let c = 0; c < m; c++) {
                if (!avail[r][c]) continue;
                const lo = Math.max(0, c - vBound);
                const hi = Math.min(m - 1, c + vBound);
                let s = (prefix[hi + 1] - prefix[lo]) % MOD;
                if (s < 0n) s += MOD;
                newFalse[c] = s;
            }
        }
        const newTrue = lateralPass(newFalse, avail[r]);
        rowTotal = new Array(m);
        for (let c = 0; c < m; c++) rowTotal[c] = (newFalse[c] + newTrue[c]) % MOD;
    }

    let ans = 0n;
    for (let c = 0; c < m; c++) ans = (ans + rowTotal[c]) % MOD;
    return Number(ans);
};
